type Handler = (this: Toolbar, value: any) => void;

const sharedToolbars = new WeakMap<HTMLElement, SharedToolbar>();

class SharedToolbar {
  toolbars = new Set<Toolbar>();
  controls: [string, HTMLElement][] = [];
  active: Toolbar | null = null;
  observer: MutationObserver;
  documentObserver: MutationObserver;

  constructor(readonly container: HTMLElement) {
    this.attachControls();
    this.observer = new MutationObserver(() => {
      this.removeDisconnectedToolbars();
      this.attachControls();
    });
    this.observer.observe(container, { childList: true, subtree: true });
    // An editor can be removed without its toolbar being removed with it.
    this.documentObserver = new MutationObserver(() =>
      this.removeDisconnectedToolbars(),
    );
    this.documentObserver.observe(document.body, {
      childList: true,
      subtree: true,
    });
  }

  add(toolbar: Toolbar) {
    this.toolbars.add(toolbar);
    toolbar.controls = this.controls;
    // Preserve the long-standing single-editor behavior. Once a container is
